-- Import the ngx module which provides access to numerous facilities, including variable and pattern matching capabilities.
local http = require("resty.http")
local server_api="your_openresty_server_ip:port/"
ngx.config.set_header("X-Custom", "my-custom")
-- create an http client object
local httpc = http.new()

